import{_ as i,o as l,c as e,a}from"./app-7c057b3f.js";const r={},h=a('<h1 id="更新日志" tabindex="-1"><a class="header-anchor" href="#更新日志" aria-hidden="true">#</a> 更新日志</h1><h4 id="ver-0-9-7-1-2023-11-24" tabindex="-1"><a class="header-anchor" href="#ver-0-9-7-1-2023-11-24" aria-hidden="true">#</a> Ver 0.9.7.1 - 2023.11.24</h4><ul><li>属性表新增字段统计、汇总工具</li><li>支持多部件合并，多部件和多段线合并，优化多部件标注</li><li>新增【坐标导入】工具，可导入 csv、txt、dat、xls等格式的点坐标，命令 ZBDR</li><li>影像图层增加【属性】功能，可查看影像基本信息</li><li>优化【拓扑检查】过滤器，支持 按属性选择 语法</li><li>修复在线地图部分行政区域缺失问题，支持搜索</li><li>导出影像支持投影变换</li></ul><h4 id="ver-0-9-6-1-2023-11-12" tabindex="-1"><a class="header-anchor" href="#ver-0-9-6-1-2023-11-12" aria-hidden="true">#</a> Ver 0.9.6.1 - 2023.11.12</h4><ul><li>新增【栅格裁剪】工具，可批量裁剪多张栅格图像，命令 CIMG</li><li>栅格处理系列工具参数优化，增加可配置项目</li><li>工具箱优化，可收起，支持自定义图标</li><li>打印工具优化，可指定铺满图纸或缩放至指定倍率</li></ul><h4 id="ver-0-9-6-0-2023-11-02" tabindex="-1"><a class="header-anchor" href="#ver-0-9-6-0-2023-11-02" aria-hidden="true">#</a> Ver 0.9.6.0 - 2023.11.02</h4><ul><li>新增【属性计算器】，可通过计算字段的方式批量修改实体属性</li><li>优化【字段标注】，可标注重量线，表达式支持SOUTH；</li><li>优化【图层列表】，支持多选批量调整图层状态</li><li>优化【工具箱】，支持折叠</li><li>优化【空间连接】文字内容提取到面，可提取多个文字</li><li>优化【属性值】面板，修复</li><li>优化【影像合并】【影像裁剪】等栅格工具；</li></ul><h4 id="ver-0-9-5-0-2023-10-15" tabindex="-1"><a class="header-anchor" href="#ver-0-9-5-0-2023-10-15" aria-hidden="true">#</a> Ver 0.9.5.0 - 2023.10.15</h4><ul><li>新增【坐标转换】功能，支持投影变换、四参数转换、七参数转换，命令 ZBZH；</li><li>新增【坐标注记】功能，命令 ZBZJ，支持批量注记；</li><li>新增【边长注记】功能，命令 BCZJ；</li><li>新增【工具箱自定义】功能，可自定义命令到工具箱；</li><li>窗体新增【帮助】按钮，可快速定位在线帮助；</li><li>修复部分命令卡死和冲突问题，部分功能优化；</li><li>修复部分QQ授权失效问题；</li><li>启动器中加入【卸载】功能；</li></ul><h4 id="ver-0-9-4-0-2023-09-21" tabindex="-1"><a class="header-anchor" href="#ver-0-9-4-0-2023-09-21" aria-hidden="true">#</a> Ver 0.9.4.0 - 2023.09.21</h4><ul><li>新增【在线地图】行政区域相关功能，可直接查看行政界线</li><li>修复【在线地图】部分图源投影后背景不透明问题，优化墨卡托中国坐标系的精度和速度</li><li>下载【在线地图】支持多部件</li><li>修复【空间连接】文字为图斑赋值时，因用户字体缺失导致的问题</li></ul><h4 id="ver-0-9-3-2-2023-09-05" tabindex="-1"><a class="header-anchor" href="#ver-0-9-3-2-2023-09-05" aria-hidden="true">#</a> Ver 0.9.3.2 - 2023.09.05</h4><ul><li>修复部分在线地图投影后颜色变红问题</li><li>坐标系选择界面加入【图层】节点，便于直接选取图层的空间参考</li><li>修复部分新设备授权失败问题</li></ul><h4 id="ver-0-9-3-1-2023-09-01" tabindex="-1"><a class="header-anchor" href="#ver-0-9-3-1-2023-09-01" aria-hidden="true">#</a> Ver 0.9.3.1 - 2023.09.01</h4><ul><li>支持多部件标注，支持保存和加载标注配置</li><li>新增【沿线注记】工具，命令 <code>LLF</code>,可沿多段线标注指定字段</li><li>新增【梯形分幅】工具，命令 <code>GGT</code>，可构建标准分幅图</li><li>新增【构建光栅结合图】工具，命令 <code>BIMGE</code>，无需加载图像即可构建结合图</li><li>添加了部分 <strong>天地图</strong> 和 <strong>星图地球</strong> 图源</li><li>修复【在线地图】部分投影范围出错问题</li><li>修复多部件多边形导入 Hatch 失败的问题</li><li>修复部分电脑加载后提示“未知命令”问题</li></ul><h4 id="ver-0-9-3-0-2023-08-22" tabindex="-1"><a class="header-anchor" href="#ver-0-9-3-0-2023-08-22" aria-hidden="true">#</a> Ver 0.9.3.0 - 2023.08.22</h4><ul><li>优化【KML】导入导出，支持 ArcGIS 导出的KML字段，支持字段描述</li><li>修复【TileMap】导出图源失败问题，界面优化</li><li>新增【简化面】功能，可在简化时维持相邻面拓扑结构</li><li>优化【矩形分幅】工具，添加选项和比例尺</li><li>优化【拓扑检查】，加入进度提示与结果排序，叠加检查性能优化</li><li>优化 Windows 缩放导致的一些问题，指南搜索关键词DPI查看</li><li>提供【在线指南】，命令 <code>SHELP</code></li></ul><h4 id="ver-0-9-2-6-2023-07-16" tabindex="-1"><a class="header-anchor" href="#ver-0-9-2-6-2023-07-16" aria-hidden="true">#</a> Ver 0.9.2.6 - 2023.07.16</h4><ul><li>新增对【GeoPackage】矢量格式的读写支持</li><li>新增【属性块】相关功能，可将属性块内容提取到字段，将字段内容更新到属性块</li><li>新增【启动图标】，位于CAD状态栏右下角，点击可快速开关内容列表</li><li>优化【工具箱】，可通过首字母打开工具集，如：栅格工具(SG)，属性管理(SX)</li><li>优化【多部件块】，可双击直接进行编辑（或命令BBE编辑）</li><li>优化【全局设置】，去掉一些无用的项</li><li>优化【快捷命令】，PGP 查看</li></ul><h4 id="ver-0-9-2-5-2023-06-27" tabindex="-1"><a class="header-anchor" href="#ver-0-9-2-5-2023-06-27" aria-hidden="true">#</a> Ver 0.9.2.5 - 2023.06.27</h4><ul><li>新增【高清截图】功能，可截取不同尺寸及分辨率图片，支持批量截取，命令 GQJT</li><li>新增【土地报备】相关功能，可导入导出报备坐标文件，命令 BBDR，BBDC</li><li>优化【批量打印】系列工具，支持纸张自适应图框</li><li>优化【挂接外部数据】，支持加载和保存配置，支持追加字段</li><li>优化【内容列表】，鼠标中键单击可改变面板停靠方式</li><li>修复【批量插入DWG】同名块插入错误问题</li><li>修复【光栅图像】加载错误问题，对支持的格式进行检查提示</li></ul><h4 id="ver-0-9-2-4-2023-06-05" tabindex="-1"><a class="header-anchor" href="#ver-0-9-2-4-2023-06-05" aria-hidden="true">#</a> Ver 0.9.2.4 - 2023.06.05</h4><ul><li>新增 【字段转文字】 功能，可将文字内容修改为指定字段值，命令 ZDZWZ</li><li>优化 【空间选择】 工具，添加 要素边界 相关空间关系</li><li>修复字段内容过长导致的截取问题，优化属性表</li><li>修复字段计算器代码块问题，计算速度优化</li><li>修复【挂接外部数据】字段类型不匹配问题</li><li>优化【合并为多部件】工具，多部件属性继承自最大面</li><li>优化启动器，启动器和【关于】界面可检查下载最新版本</li></ul><h4 id="ver-0-9-2-3-2023-05-21" tabindex="-1"><a class="header-anchor" href="#ver-0-9-2-3-2023-05-21" aria-hidden="true">#</a> Ver 0.9.2.3 - 2023.05.21</h4><ul><li>字段计算器添加 Area，Length 等函数</li><li>添加【挂接外部数据】功能，命令 GJSJ</li><li>调整图源管理方式，可直接拖动LRC加载图源（优化中...）</li><li>修复打印工具，按范围打印自适应打印范围</li><li>修复 影像合并 失败问题</li><li>工具箱修改为选项卡结构</li></ul><h4 id="ver-0-9-2-2-2023-04-28" tabindex="-1"><a class="header-anchor" href="#ver-0-9-2-2-2023-04-28" aria-hidden="true">#</a> Ver 0.9.2.2 - 2023.04.28</h4><ul><li>安装包拆分为32位和64位版本，独立发布</li><li>提供便携版本，安装卸载更加方便快捷</li><li>添加对 AutoCAD2023-2024 的支持，目前支持 AutoCAD2013-2024 所有版本</li><li>字段计算器支持自定义函数（类似ArcGIS的代码块）</li><li>字段计算器添加 GetXdata 和 SetXdata 函数，用于直接提取和计算扩展属性</li><li>优化属性表速度，属性选择视图和CAD选择集维持一致</li><li>修改多值字段编辑方式，双击可直接编辑（如 SOUTH 字段）</li><li>矢量和栅格支持批量加载</li><li>在线地图动态投影支持自定义坐标系</li><li>修复下载的 TIFF 无法通过光栅图像加载的问题</li><li>添加“快捷命令编辑器”，位于：工具箱-&gt;快捷命令</li><li>添加传统菜单栏，同步工具箱所有功能，命令 SMENU 开启</li><li>添加 填充合并 ，填充拆分 功能；</li><li>优化启动工具，优化加载速度</li><li>提供QQ授权功能，用于跨设备使用</li></ul><h4 id="ver-0-9-2-1-2023-03-13" tabindex="-1"><a class="header-anchor" href="#ver-0-9-2-1-2023-03-13" aria-hidden="true">#</a> Ver 0.9.2.1 - 2023.03.13</h4><ul><li>支持 AutoCAD2013-2022 所有版本</li><li>在线地图速度优化，投影校正优化</li><li>在线地图下载功能优化，自动校正火星坐标系图源</li><li>添加了一些在线地图图源</li><li>影像加载和浏览速度优化</li><li>新增影像导出功能（格式转换）</li><li>新增影像分割，合并功能</li><li>新增影像轮廓提取功能</li><li>新增光栅图像轮廓自适应功能</li><li>更多栅格格式的支持（tif,img,gpkg,vrt,jpg,jg2,png,sqlite,mbtile,hdr,ehdr）</li><li>新增对文件地理数据库（GDB）弧段的支持</li><li>支持多部件多边形</li><li>支持图层投影定义</li><li>支持导入导出时进行投影变换</li><li>优化对中文路径和中文字符串的支持</li><li>新增对CSV文件支持</li><li>属性表速度优化</li><li>字段计算器功能扩展，增加支持的语法，可执行更复杂的计算任务</li><li>新增&quot;输入拦截&quot;功能，自动切换英文输入法</li><li>新增构建结合图表功能（GGG）</li><li>优化快捷键模块，避免和PGP文件冲突</li><li>绘图模块优化</li></ul>',29),d=[h];function t(n,c){return l(),e("div",null,d)}const o=i(r,[["render",t],["__file","changelog.html.vue"]]);export{o as default};
